            //
            aOrbiterA = ((aOrbiterA + aOrbiterK) + 5004087958637038973U) + aOrbiterUpdateSaltA[((aIndex + 26U)) & S_SALT1];
            aOrbiterD = (aOrbiterD ^ aOrbiterA) ^ 7176881295123125567U;
            aOrbiterD = RotL64((aOrbiterD * 15272157962928021009U), 53U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterH) + 10889800478505074438U;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterC) ^ 13728832441482547824U) ^ aOrbiterUpdateSaltE[((aIndex + 13U)) & S_SALT1];
            aOrbiterJ = RotL64((aOrbiterJ * 17588477761978646139U), 37U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterI) + 17345665880706866772U;
