            //
            aWandererF = aWandererF + ((((RotL64(aScatter, 37U) + RotL64(aOrbiterA, 3U)) + aOrbiterE) + aNonceWordG) + aWandererUpdateSaltA[((aIndex + 25U)) & S_SALT1]);
