            aCross = RotL64(aScrapLaneA[((S_BLOCK1 - aIndex + 8554U)) & S_BLOCK1], 52U) ^ RotL64(pSnow[((S_BLOCK1 - aIndex + 6065U)) & S_BLOCK1], 27U);
            aCross = TwistMix64::DiffuseB(((aCross ^ aDomainWordCross) ^ aNonceWordM));
