            aOrbiterD = (aWandererJ + RotL64(aScatter, 27U)) + 888475203006174856U;
            aOrbiterI = ((aWandererA + RotL64(aIngress, 53U)) + 3649183529366307877U) + aNonceWordD;
            aOrbiterF = ((aWandererC + RotL64(aCross, 47U)) + RotL64(aCarry, 37U)) + 4642631047518805167U;
            aOrbiterG = ((aWandererK + RotL64(aPrevious, 29U)) + 6108329730724782250U) + aNonceWordI;
            aOrbiterA = ((aWandererG + RotL64(aScatter, 41U)) + 8334054653023816636U) + aOrbiterAssignSaltD[(((31U - aIndex) + 9U)) & S_SALT1];
            aOrbiterB = (aWandererB + RotL64(aCross, 20U)) + 5891895375031474350U;
            aOrbiterH = ((((aWandererI + RotL64(aPrevious, 51U)) + RotL64(aCarry, 43U)) + 3176720746238477862U) + aOrbiterAssignSaltB[((aIndex + 8U)) & S_SALT1]) + aNonceWordN;
