            //
            aOrbiterC = ((aOrbiterC + aOrbiterK) + 17005063057791320948U) + aOrbiterUpdateSaltE[((aIndex + 24U)) & S_SALT1];
            aOrbiterD = (aOrbiterD ^ aOrbiterC) ^ 18333780598768130670U;
