            //
            aOrbiterJ = (aOrbiterJ + aOrbiterI) + 2056115016443263153U;
            aOrbiterF = (aOrbiterF ^ aOrbiterJ) ^ 10245512728872962677U;
            aOrbiterF = RotL64((aOrbiterF * 707106795383284903U), 5U);
            //
            aOrbiterE = (((aOrbiterE + aOrbiterG) + 4810366069422162351U) + aOrbiterUpdateSaltD[((aIndex + 27U)) & S_SALT1]) + aNonceWordE;
            aOrbiterI = (((aOrbiterI ^ aOrbiterE) ^ 3051442983125942469U) ^ aOrbiterUpdateSaltF[(((31U - aIndex) + 10U)) & S_SALT1]) ^ aNonceWordB;
            aOrbiterI = RotL64((aOrbiterI * 13558537578054436423U), 57U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterC) + 9285068547223654308U) + aOrbiterUpdateSaltB[(((31U - aIndex) + 11U)) & S_SALT1];
            aOrbiterG = (aOrbiterG ^ aOrbiterA) ^ 13067251130180968842U;
